#include <memory>
#include <string>
#include <unordered_map>
#include <stdexcept>

class Shape
{
public:
    virtual ~Shape() = default;
    virtual double area() const = 0;
};

class Circle : public Shape
{
private:
    double radius_;
public:
    explicit Circle(double radius) : radius_(radius) {}
    double area() const override
    {
        return 3.14159265358979323846 * radius_ * radius_;
    }
};

class Square : public Shape
{
private:
    double side_;
public:
    explicit Square(double side) : side_(side) {}
    double area() const override
    {
        return side_ * side_;
    }
};

std::unique_ptr<Shape> make_shape(const std::string& name, double param)
{
    static const std::unordered_map<std::string, std::unique_ptr<Shape>(*)(double)> creators = {
        {"circle", [](double r) { return std::unique_ptr<Shape>(new Circle(r)); }},
        {"square", [](double s) { return std::unique_ptr<Shape>(new Square(s)); }}
    };

    auto it = creators.find(name);
    if (it != creators.end())
    {
        return it->second(param);
    }
    throw std::invalid_argument("Unknown shape type");
}
